INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (1, 4, 10011, "【加速】4以上：\nＴＰ上昇＋30\n重複可能の行動速度＋100％\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (1, 9, 10012, "【加速】9以上：\nユニオンバースト発動時に【烈風】＋１（最大99）\n20秒ごとに物理/魔法与ダメアップフィールド展開\n（【烈風】数×1％）\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (1, 15, 10013, "【加速】15以上：\n9秒ごとにＴＰ1000回復\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (2, 4, 10021, "【弱体】4以上：\n敵全体に黒炎付与（毎秒1万ダメージ、毎回5％ずつダメージ上昇）\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (2, 9, 10022, "【弱体】9以上：\n敵への継続ダメージ＋1000％（最大50万ダメージ）\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (2, 15, 10023, "【弱体】15以上：\n弱体効果数に応じて敵の被ダメアップ（対象の弱体効果数\n×50％、最大＋500％）\nさらに敵への継続ダメージ＋1000％（最大50万ダメージ）\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (3, 4, 10031, "【会心】4以上：\n物理/魔法クリダメアップ（【会心】数×10％）\n物理/魔法クリティカルアップ（【会心】数×400）\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (3, 9, 10032, "【会心】9以上：\n敵全体に物理/魔法被クリダメアップ（【会心】数×5％）\nダメージブースト（【会心】数×2％）\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (3, 15, 10033, "【会心】15以上：\n攻撃時追加ダメージ（【会心】数×2％）\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (4, 4, 10041, "【強化】4以上：\nバトル開始20秒後、物理/魔法攻撃力アップフィールド展開（現在値＋30％）\n敵へのダメージ減衰量緩和\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (4, 9, 10042, "【強化】9以上：\nさらにバトル開始40秒後、物理/魔法攻撃力アップフィールド展開（現在値＋50％）\nさらに敵へのダメージ減衰量緩和\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (4, 15, 10043, "【強化】15以上：\nさらにバトル開始60秒後、物理/魔法攻撃力アップフィールド展開（現在値＋70％）\nさらに敵へのダメージ減衰量緩和\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (5, 4, 10051, "【守備】4以上：\n全ダメージ33％カット\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (5, 9, 10052, "【守備】9以上：\nＨＰ回復量ダウン耐性付与\n味方からバフを受けるか、敵から攻撃を受けるたびに【闘志】＋１（最大50）\n【闘志】の数に応じて与ダメアップ（【闘志】数×3％）\n");
INSERT INTO `v1_bad3b388a2d5ebb60373dd454da10d3cf67f8aafece0b3c38fb3d27aa3babf32` VALUES (5, 15, 10053, "【守備】15以上：\n残りＨＰ割合に応じたダメージブースト（最大60％）\nＨＰが0になった場合、戦闘不能になる前にＨＰを100％回復（1回）\n");
